using System.ComponentModel;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = "gpt-4o-mini-2024-07-18";

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

var noteStore = new NoteStore();
var webSearcher = new WebSearcher();

var tools = new AITool[]
{
    AIFunctionFactory.Create(webSearcher.SearchAsync),
    AIFunctionFactory.Create(noteStore.TakeNote),
    AIFunctionFactory.Create(noteStore.GetNotes),
};

var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. Given a topic, you research it thoroughly by
        searching the web multiple times with varied queries, taking notes on
        key findings, and then producing a well-organized summary.

        Workflow:
        1. Break the topic into 2-3 specific search queries.
        2. For each query, call SearchWeb and review the results.
        3. Call TakeNote to record important facts, statistics, or insights.
        4. After gathering enough information, call GetNotes to review everything.
        5. Produce a final, concise summary with the key findings organized by theme.

        Always cite where information came from when possible.
        """,
    name: "ResearchAgent",
    description: "Researches topics via web search and summarization.",
    tools: tools);

var chatOptions = new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 2048,
};

Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching \"{topic}\"...\n");

var session = await agent.CreateSessionAsync(conversationId: "research-1");
var runOptions = new ChatClientAgentRunOptions(chatOptions);

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a detailed summary: {topic}",
    session,
    runOptions))
{
    Console.Write(update.Text);
}

Console.WriteLine();

// ---------------------------------------------------------------------------
// Tool: Web Search (via DuckDuckGo HTML lite)
// ---------------------------------------------------------------------------
sealed partial class WebSearcher
{
    private static readonly HttpClient Http = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
        },
        Timeout = TimeSpan.FromSeconds(15),
    };

    [Description("Searches the web for a query and returns a list of result snippets.")]
    public async Task<string> SearchAsync(
        [Description("The search query to look up on the web.")] string query)
    {
        try
        {
            var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
            var html = await Http.GetStringAsync(url);

            var results = new StringBuilder();
            int count = 0;

            foreach (Match m in ResultPattern().Matches(html))
            {
                if (++count > 5) break;

                var title = StripHtml(m.Groups["title"].Value).Trim();
                var snippet = StripHtml(m.Groups["snippet"].Value).Trim();

                if (!string.IsNullOrWhiteSpace(title))
                {
                    results.AppendLine($"[{count}] {title}");
                    if (!string.IsNullOrWhiteSpace(snippet))
                        results.AppendLine($"    {snippet}");
                    results.AppendLine();
                }
            }

            return results.Length > 0
                ? results.ToString()
                : "No results found for this query.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [GeneratedRegex(
        @"<a[^>]+class=""result__a""[^>]*>(?<title>.*?)</a>.*?<a[^>]+class=""result__snippet""[^>]*>(?<snippet>.*?)</a>",
        RegexOptions.Singleline)]
    private static partial Regex ResultPattern();

    private static string StripHtml(string html)
        => Regex.Replace(html, "<.*?>", string.Empty)
            .Replace("&amp;", "&")
            .Replace("&lt;", "<")
            .Replace("&gt;", ">")
            .Replace("&quot;", "\"")
            .Replace("&#x27;", "'")
            .Trim();
}

// ---------------------------------------------------------------------------
// Tool: Note Store
// ---------------------------------------------------------------------------
sealed class NoteStore
{
    private readonly List<(string Title, string Content)> _notes = [];

    [Description("Saves a research note with a title and content for later reference.")]
    public string TakeNote(
        [Description("Short title for this note.")] string title,
        [Description("The content or findings to record.")] string content)
    {
        _notes.Add((title, content));
        return $"Note #{_notes.Count} saved: \"{title}\"";
    }

    [Description("Retrieves all saved research notes collected so far.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been saved yet.";

        var sb = new StringBuilder();
        for (int i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"--- Note #{i + 1}: {_notes[i].Title} ---");
            sb.AppendLine(_notes[i].Content);
            sb.AppendLine();
        }
        return sb.ToString();
    }
}

